final:
module RefModule (
    input [15:0] data,
    input [1:0] control,
    output reg [15:0] out
);
  wire [15:0] _tap_data = data & {16{1'b1}};

    always @(*) begin
        case (control)
            2'b00: out = data;
            2'b01: out = data << 1;
            2'b10: out = data >> 1;
            2'b11: out = data;
            default: out = 16'b0;
        endcase
    end
endmodule
